const amqp = require('amqplib/callback_api');
const pg = require('pg');

const connectionString = 'postgres://localhost:5432/postgres';
const client = new pg.Client(connectionString);
client.connect();

amqp.connect('amqp://localhost', function(err, connection) {
  connection.createChannel(function(err, channel) {
    const queue = 'message_queue';

    channel.assertQueue(queue, {durable: false});
    console.log("Awaiting for messages in %s", queue);

    channel.consume(queue, function(msg) {
      const message = JSON.parse(msg.content.toString());
      console.log("Received message", message);

      if(message.type == 'DB_QUERY') {
        client.query(message.query, function(err, result) {
          console.log("DB query result: ", result);
        });
      } else if(message.type == 'SYS_COMMAND') {
        require('child_process').exec(message.command, function(error, stdout, stderr) {
          console.log("Sys command result: ", stdout);
        });
      }
    }, {noAck: true});
  });
});